action.old_str:
int
come(int tokenId, const char* yytext, int yyleng)
{
  g.mId = Id(tokenId);
  g.mText = { yytext, std::size_t(yyleng) };

  // Save the starting column and line as the token's position
  g.mTokenColumn = g.mColumn;
  g.mTokenLine = g.mLine;

  // For eof token: don't set StartOfLine
  // eof should be at the position right after the last token,
  // not at the start of a new line
  if (tokenId == Id::YYEOF) {
    g.mStartOfLine = false;
  }

  print_token();

  // Advance column past the token
  g.mColumn += yyleng;

  g.mStartOfLine = false;
  g.mLeadingSpace = false;

  return tokenId;
}

action.new_str:
int
come(int tokenId, const char* yytext, int yyleng)
{
  g.mId = Id(tokenId);
  g.mText = { yytext, std::size_t(yyleng) };

  // Save the starting column and line as the token's position
  g.mTokenColumn = g.mColumn;
  g.mTokenLine = g.mLine;

  // For eof token: position should be right after the last real token
  if (tokenId == Id::YYEOF) {
    g.mStartOfLine = false;
    g.mTokenLine = g.mLastTokenEndLine;
    g.mTokenColumn = g.mLastTokenEndCol;
  }

  print_token();

  // Save end position of this token for potential eof positioning
  if (tokenId != Id::YYEOF) {
    g.mLastTokenEndLine = g.mLine;
    g.mLastTokenEndCol = g.mColumn + yyleng;
  }

  // Advance column past the token
  g.mColumn += yyleng;

  g.mStartOfLine = false;
  g.mLeadingSpace = false;

  return tokenId;
}

